import{_ as t,c as d,o as a,R as r}from"./chunks/framework.CIzs38F0.js";const b=JSON.parse('{"title":"pg数据库data目录","description":"","frontmatter":{},"headers":[],"relativePath":"guide/Database/pgSql/base/3-dir.md","filePath":"guide/Database/pgSql/base/3-dir.md","lastUpdated":1711535325000}'),e={name:"guide/Database/pgSql/base/3-dir.md"},p=r('<h1 id="pg数据库data目录" tabindex="-1">pg数据库data目录 <a class="header-anchor" href="#pg数据库data目录" aria-label="Permalink to &quot;pg数据库data目录&quot;">​</a></h1><p>pg数据库和mysql数据库的安装目录结构很类似，程序和数据是分开的，在启动时候可以自行指定不同的数据目录来做到启动不同的数据库</p><p>释pg数据目录下，每个文件夹以及文件名的作用</p><table><thead><tr><th>目录名</th><th>作用</th></tr></thead><tbody><tr><td>base</td><td>该目录包含了数据库中各个数据库，每个数据库都是由一个文件夹组成，文件名是该数据库的oid，这个可以通过数据字典pg_database来查看对应的数据库名(select oid,datname from pg_database)。</td></tr><tr><td>pg_xlog/pg_wal</td><td>该目录包含wal(预写)日志。注意在10版本后，该目录重命名为&quot;pg_wal&quot;。</td></tr><tr><td>global</td><td>该目录包含集群范围的各个表和相关视图。 （ pg_database、 pg_tablespace ）</td></tr><tr><td>pg_clog</td><td>该目录包含事务提交状态数据。</td></tr><tr><td>pg_multixact</td><td>该目录包含多事务状态数据（等待锁定的并发事务）</td></tr><tr><td>pg_notify</td><td>该目录包含LISTEN/NOTIFY状态数据。</td></tr><tr><td>pg_serial</td><td>该目录包含了已经提交的序列化事务的有关信息。</td></tr><tr><td>pg_snapshots</td><td>该目录包含导出的快照。</td></tr><tr><td>pg_stat_tmp</td><td>该目录包含统计子系统的临时文件。</td></tr><tr><td>pg_subtrans</td><td>该目录包含子事务状态数据。</td></tr><tr><td>pg_tblspc</td><td>该目录包含表空间的符号链接。</td></tr><tr><td>pg_twophase</td><td>该目录包含预备事务的状态文件。</td></tr><tr><td>pg_commit_ts</td><td>该目录包含已提交事务的时间。</td></tr><tr><td>pg_dynshmem</td><td>该目录包含动态共享内存子系统使用的件。</td></tr><tr><td>pg_logical</td><td>该目录包含逻辑解码的状态数据。</td></tr><tr><td>pg_replslot</td><td>该目录包含复制槽数据。</td></tr><tr><td>pg_stat</td><td>该目录包含统计子系统的永久文件。</td></tr></tbody></table><hr><table><thead><tr><th>文件名</th><th>作用</th></tr></thead><tbody><tr><td>pg_hba.conf</td><td>数据库访问控制文件，一般新安装的数据库都需要进行配置，在流复制中也需要配置。</td></tr><tr><td>pg_ident.conf</td><td>将数据库用户映射到本地用户的一种认证方式，使用比较少，在特殊场景下需要配置（控制哪一个本地用户可以连接到哪一个数据库）。</td></tr><tr><td>postgresql.conf/postgresql.auto.conf</td><td>主要配置文件，在数据库安装完后，需要手动更改里面的监听地址，否则默认只能本地连接。</td></tr><tr><td>PG_VERSION</td><td>包含版本信息。</td></tr><tr><td>postmaster.pid</td><td>启动后pg主进程ID</td></tr></tbody></table>',6),s=[p];function _(o,g,l,i,c,n){return a(),d("div",null,s)}const m=t(e,[["render",_]]);export{b as __pageData,m as default};
